def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 12):
                base_val = np.sin(ratio * a * np.pi) + np.cos(ratio * (a + 1))
                multiplier = (a ** 3) / (a + 1)
                temp = np.exp(-ratio * a * 2) * base_val * multiplier
                if a % 4 == 1:
                    temp *= 1.1
                elif a % 4 == 3:
                    temp *= 0.92
                score += temp
            if (capacity + item) % 4 == 0 and (capacity * item) % 7 == 0:
                score *= 0.75
            if capacity < 10:
                score *= 2.5
            if score > 20:
                score /= 3.7
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity * 0.75) + 3):
                val = ratio + (n / (n + 2)) + np.tanh(ratio * n)
                prod *= val if val > 0 else 1
                if prod > 5e5:
                    prod = np.sqrt(prod)
                    break
            mod_val = int(prod * 3) % 400
            score += np.log1p(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 3) % 4 == 0):
                score += 6
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                val = ((ratio * x ** 3) % 1) * (x ** 1.8)
                extra_sum += val * np.sin(x)
            score += extra_sum / 6
            score += np.cbrt(score + 1)
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = ((ratio + 0.1) ** (m + 3)) * (m ** 3.1) / ((m + 1.5) ** 1.1)
                score += increment * np.log1p(m)
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.4
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 11):
                term = ((ratio - 0.5) ** p) * (p ** 2) * np.cos(p * ratio)
                penalty_base += term
                if penalty_base > 60:
                    penalty_base = np.log1p(abs(penalty_base))
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 6) % 8 == 0) and (int(item * 7) % 9 == 0):
                score -= 8
            if score < 0:
                score = abs(score) * 1.7 + 6
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 13):
                term = ((diff + 0.03) ** q) * (q ** 3) / (q + 0.5) * np.sin(q * diff * np.pi / 2)
                penalty_ext += term
            score = penalty_ext * 22
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 5 == 0):
                score -= 10
            for z in range(1, 7):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.1) * np.cos(z)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1500:
                score = 1500
        elif 1.2 < ratio <= 1.8:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5) * np.exp(-r / 5) * np.tanh(diff * r)
                if term > 15000:
                    term = np.sqrt(term) * 1.2
                super_penalty += term
                if super_penalty > 20000:
                    super_penalty = np.log1p(super_penalty)
                    break
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 7 == 0) and (int(item * 20) % 6 == 0):
                score -= 15
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5) * np.sin(w * 1.3)
            if score < 0:
                score = abs(score) * 0.8 + 5
            if score > 2500:
                score = 2500
        else:
            ultimate_penalty = 0
            diff = ratio - 1.8
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 4) * np.cos(s * diff) * np.exp(-s / 7)
                if term > 20000:
                    term = np.sqrt(term) * 1.5
                ultimate_penalty += term
                if ultimate_penalty > 35000:
                    ultimate_penalty = np.log1p(ultimate_penalty)
                    break
            score = ultimate_penalty * 40
            if capacity < item * 3:
                score += 40
            if (int(capacity * 20) % 9 == 0) and (int(item * 25) % 7 == 0):
                score -= 20
            for u in range(3, 11):
                score += ((diff / u) % 1) * (u * 3) * np.sin(u * 0.7)
            if score < 0:
                score = abs(score) * 0.9 + 7
            if score > 3500:
                score = 3500
        if capacity > 500:
            score /= (np.log1p(capacity) + 2.5)
        elif capacity < 8:
            score *= 3.1
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q3)
        median_val = q2
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
